<?php require_once __DIR__.'/../includes/auth_check.php';$title='Ajouter voiture';$error='';if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??'')){try{$img=upload_img($_FILES['image']??[]);$slug=trim($_POST['slug']??'')?:slugify($_POST['name']??'');$st=$pdo->prepare('INSERT INTO cars (agency_id,name,slug,category,transmission,fuel_type,seats,price_per_day,image_path,description,features,deposit_info,documents_required,insurance_info,status) VALUES (1,:name,:slug,:category,:transmission,:fuel_type,:seats,:price,:image,:description,:features,:deposit,:docs,:insurance,:status)');$st->execute(['name'=>trim($_POST['name']),'slug'=>$slug,'category'=>trim($_POST['category']),'transmission'=>trim($_POST['transmission']),'fuel_type'=>trim($_POST['fuel_type']),'seats'=>(int)$_POST['seats'],'price'=>(float)$_POST['price_per_day'],'image'=>$img,'description'=>trim($_POST['description']),'features'=>trim($_POST['features']),'deposit'=>trim($_POST['deposit_info']),'docs'=>trim($_POST['documents_required']),'insurance'=>trim($_POST['insurance_info']),'status'=>$_POST['status']]);redirect('/admin/cars/');}catch(Throwable $e){$error='Impossible d’enregistrer la voiture.';}}include __DIR__.'/../includes/admin_header.php';?><h1>Ajouter une voiture</h1><?php if($error):?><p class="error"><?=e($error)?></p><?php endif;?><form method="post" enctype="multipart/form-data" class="admin-form"><?=csrf_field()?><label>Nom<input name="name" value="<?=e($car['name']??'')?>" required></label><label>Slug<input name="slug" value="<?=e($car['slug']??'')?>"></label><label>Catégorie<input name="category" value="<?=e($car['category']??'Economique')?>" required></label><label>Transmission<select name="transmission"><option>Manuelle</option><option>Automatique</option></select></label><label>Carburant<input name="fuel_type" value="<?=e($car['fuel_type']??'Diesel')?>" required></label><label>Places<input type="number" name="seats" value="<?=e($car['seats']??5)?>"></label><label>Prix / jour<input type="number" step="0.01" name="price_per_day" value="<?=e($car['price_per_day']??'300')?>" required></label><label>Image<input type="file" name="image" accept="image/jpeg,image/png,image/webp"></label><label>Description<textarea name="description"><?=e($car['description']??'')?></textarea></label><label>Features<textarea name="features"><?=e($car['features']??'')?></textarea></label><label>Caution<textarea name="deposit_info"><?=e($car['deposit_info']??'')?></textarea></label><label>Documents<textarea name="documents_required"><?=e($car['documents_required']??'')?></textarea></label><label>Assurance<textarea name="insurance_info"><?=e($car['insurance_info']??'')?></textarea></label><label>Statut<select name="status"><option value="available">Disponible</option><option value="rented">Louée</option><option value="maintenance">Maintenance</option><option value="hidden">Masquée</option></select></label><button class="btn primary">Enregistrer</button></form><?php include __DIR__.'/../includes/admin_footer.php';?>